const body = $input.first().json.body ?? $input.first().json;
const {
  original_appointment_id,
  patient_id, doctor_id, calendar_source_id,
  summary, notes,
  service_ids,
  start, end,
  changed_by,
} = body || {};

if (!original_appointment_id) throw new Error('original_appointment_id is required');
if (!patient_id) throw new Error('patient_id is required');
if (!doctor_id) throw new Error('doctor_id is required');
if (!start || !end) throw new Error('start and end are required');
if (!summary) throw new Error('summary is required');

const esc = (v) => v == null ? null : String(v).replace(/'/g, "''");

// Numeric FK columns must be interpolated unquoted as raw SQL.
const numOrNull = (v) => {
  if (v == null || v === '') return 'NULL';
  const n = Number(v);
  if (!Number.isFinite(n)) throw new Error(`Invalid numeric id: ${v}`);
  return String(n);
};

return [{ json: {
  original_appointment_id: esc(original_appointment_id),
  patient_id: esc(patient_id),
  doctor_id: esc(doctor_id),
  calendar_source_id_sql: numOrNull(calendar_source_id),
  summary: esc(summary),
  notes: notes ? esc(notes) : null,
  service_ids: Array.isArray(service_ids) ? service_ids.map(esc) : [],
  start_datetime: esc(start),
  end_datetime: esc(end),
  changed_by: changed_by ? esc(changed_by) : null,
} }];

const loaded = $input.all().filter(r => r.json.id);
if (loaded.length === 0) {
  return [{ json: { __error: true, code: 404, message: 'Original appointment not found' } }];
}

const current = loaded[0].json;
const input = $('Parse Input').first().json;
const from_status = String(current.status || '').toLowerCase();
const TERMINAL = ['completed', 'cancelled', 'no_show'];
if (TERMINAL.includes(from_status)) {
  return [{ json: { __error: true, code: 409, message: `Cannot reschedule an appointment in '${from_status}' state` } }];
}

return [{ json: { ...input, from_status } }];

const rows = $input.all().filter(r => r.json.new_id);
if (rows.length === 0) throw new Error('Reschedule failed — no rows returned');
const r = rows[0].json;
return [{ json: {
  success: true,
  code: 200,
  original_appointment_id: r.old_id,
  new_appointment_id: r.new_id,
} }];
